import sys

class MyQueue:

    def __init__(self):
        self.queue = []

    def push(self, x: int) -> None:
        self.queue.append(x)

    def pop(self) -> int:
        if self.empty():
            return -1
        return self.queue.pop(0)

    def peek(self) -> int:
        if self.empty():
            return -1
        return self.queue[0]

    def empty(self) -> bool:
        return len(self.queue) == 0

if __name__ == '__main__':
    q = int(sys.stdin.readline().strip())
    queue = MyQueue()
    for _ in range(q):
        queryType = int(sys.stdin.readline().strip())
        if queryType == 1:
            value = int(sys.stdin.readline().strip())
            queue.push(value)
        elif queryType == 2:
