#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class MyQueue {
private:
    vector<int> queue;
public:
    MyQueue() {}

    void push(int x) {
        queue.push_back(x);
    }

    int pop() {
        if (empty()) {
            return -1;
        }
        int front = queue[0];
        queue.erase(queue.begin());
        return front;
    }

    int peek() {
        if (empty()) {
            return -1;
        }
        return queue[0];
    }

    bool empty() {
        return queue.empty();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int q;
    cin >> q;
    MyQueue queue;
    for (int i = 0; i < q; i++) {
        int queryType;
        cin >> queryType;
        if (queryType == 1) {
            int value;
            cin >> value;
            queue.push(value);
        } else if (queryType == 2) {
            if (queue.empty()) {
                continue;
            } else {
                queue.pop();
                cout << "OK" << endl;
            }
        } else if (queryType == 3) {
            if (queue.empty()) {
                cout << "Empty" << endl;
            } else {
                cout << queue.peek() << endl;
            }
        }
    }
    return 0;
}
